/**
 * One-shot generator for `bench/fixtures/large-schema.sql`.
 * Run: `bun bench/generate-large-schema.ts`
 */
import { mkdirSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";

/** Keep fixture ≤ ~200 KiB for comfortable git + CI. */
const TABLE_COUNT = 400;
const outPath = join(import.meta.dir, "fixtures", "large-schema.sql");

const lines: string[] = [
  "-- Generated by bench/generate-large-schema.ts — do not hand-edit.",
  `BEGIN;`,
];

for (let i = 0; i < TABLE_COUNT; i++) {
  const t = `bench_big_${i}`;
  lines.push(
    `CREATE TABLE public.${t} (` +
      `id integer PRIMARY KEY GENERATED ALWAYS AS IDENTITY, ` +
      `payload text NOT NULL DEFAULT ''` +
      `);`,
  );
  lines.push(
    `CREATE INDEX ${t}_payload_idx ON public.${t} USING btree (payload);`,
  );
  lines.push(`ALTER TABLE public.${t} ENABLE ROW LEVEL SECURITY;`);
  lines.push(
    `CREATE POLICY ${t}_sel ON public.${t} FOR SELECT TO public USING (true);`,
  );
  lines.push(
    `GRANT SELECT, INSERT ON public.${t} TO anon, authenticated, service_role;`,
  );
}

lines.push(`COMMIT;`);

mkdirSync(dirname(outPath), { recursive: true });
writeFileSync(outPath, `${lines.join("\n")}\n`, "utf-8");
console.log(`Wrote ${outPath} (${TABLE_COUNT} tables)`);
